  ('social-worker-moex-04492', 'social-worker', 'social-worker-moex-110-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '身心障礙者係指身體系統構造或功能，有損傷或不全導致顯著偏離或喪失，影響其活動與參與社 會生活，經相關專業人員組成之專業團隊鑑定及評估，領有身心障礙證明者。依據身心障礙者權 益保障法，上述身體系統構造或功能之損傷或不全之規定，共計幾款？', '["6款", "8款", "12款", "15款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "43e0b296daff", "answer_pdf_sha1": "6a835a503ece", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
